import{_ as c,C as l,o as a,c as g,a2 as n,b as i,w as t,a as r,E as h,a3 as d,j as o}from"./chunks/framework.DG4H4-xE.js";const b=JSON.parse('{"title":"🎶 Orchestration vs. Choreography","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/orchestration-vs-choreography.md","filePath":"architecture/orchestration-vs-choreography.md"}'),p={name:"architecture/orchestration-vs-choreography.md"};function m(u,e,A,y,S,v){const s=l("Mermaid");return a(),g("div",null,[e[4]||(e[4]=n('<h1 id="🎶-orchestration-vs-choreography" tabindex="-1">🎶 Orchestration vs. Choreography <a class="header-anchor" href="#🎶-orchestration-vs-choreography" aria-label="Permalink to &quot;🎶 Orchestration vs. Choreography&quot;">​</a></h1><p>In microservices architecture, managing communication between services is crucial. There are two primary ways to handle these interactions: <strong>Orchestration</strong> and <strong>Choreography</strong>.</p><hr><h2 id="orchestration-the-conductor" tabindex="-1">Orchestration (The Conductor) <a class="header-anchor" href="#orchestration-the-conductor" aria-label="Permalink to &quot;Orchestration (The Conductor)&quot;">​</a></h2><p>In the Orchestration pattern, a <strong>central controller</strong> (the &quot;Orchestrator&quot;) <strong>acts as the brain</strong>. It tells each service what to do and when to do it. <strong>If a service fails, the orchestrator is responsible for handling the error or managing retries</strong>.</p><h3 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">​</a></h3><p>Think of a symphony orchestra. Every musician looks at the conductor. The musicians don&#39;t talk to each other; they wait for the conductor&#39;s signal to play their part.</p>',7)),(a(),i(d,null,{default:t(()=>[h(s,{id:"mermaid-19",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20O%20as%20Order%20Service%20(Orchestrator)%0A%20%20%20%20participant%20I%20as%20Inventory%20Service%0A%20%20%20%20participant%20P%20as%20Payment%20Service%0A%20%20%20%20participant%20S%20as%20Shipping%20Service%0A%0A%20%20%20%20O-%3E%3EI%3A%201.%20Reserve%20Items%0A%20%20%20%20I--%3E%3EO%3A%20Items%20Reserved%0A%20%20%20%20O-%3E%3EP%3A%202.%20Process%20Payment%0A%20%20%20%20P--%3E%3EO%3A%20Payment%20Success%0A%20%20%20%20O-%3E%3ES%3A%203.%20Ship%20Order%0A%20%20%20%20S--%3E%3EO%3A%20Shipped%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[r(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=n('<h3 id="pros-cons" tabindex="-1">Pros &amp; Cons <a class="header-anchor" href="#pros-cons" aria-label="Permalink to &quot;Pros &amp; Cons&quot;">​</a></h3><ul><li><strong>Pros:</strong> Centralized logic, easy to track the state of a process, simpler to implement complex workflows with many steps.</li><li><strong>Cons:</strong> The orchestrator can become a bottleneck; services are tightly coupled to the controller&#39;s logic.</li></ul><hr><h2 id="choreography-the-dance" tabindex="-1">Choreography (The Dance) <a class="header-anchor" href="#choreography-the-dance" aria-label="Permalink to &quot;Choreography (The Dance)&quot;">​</a></h2><p>In the Choreography pattern, there is <strong>no central controller</strong>. Instead, services communicate via <strong>events</strong>. Each service knows what to do when it hears a specific signal from another service.</p><h3 id="how-it-works-1" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works-1" aria-label="Permalink to &quot;How it Works&quot;">​</a></h3><p>Think of a dance troupe. There is no conductor. Each dancer knows that when their partner spins, it&#39;s their cue to jump. They react to the movements (events) of others.</p>',7)),(a(),i(d,null,{default:t(()=>[h(s,{id:"mermaid-48",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20OS%5BOrder%20Service%5D%20--%20%22OrderPlaced%20Event%22%20--%3E%20EB((Event%20Bus))%0A%20%20%20%20EB%20--%20%22OrderPlaced%22%20--%3E%20IS%5BInventory%20Service%5D%0A%20%20%20%20IS%20--%20%22ItemsReserved%20Event%22%20--%3E%20EB%0A%20%20%20%20EB%20--%20%22ItemsReserved%22%20--%3E%20PS%5BPayment%20Service%5D%0A%20%20%20%20PS%20--%20%22PaymentProcessed%20Event%22%20--%3E%20EB%0A%20%20%20%20EB%20--%20%22PaymentProcessed%22%20--%3E%20SS%5BShipping%20Service%5D%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[r(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=n('<h3 id="pros-cons-1" tabindex="-1">Pros &amp; Cons <a class="header-anchor" href="#pros-cons-1" aria-label="Permalink to &quot;Pros &amp; Cons&quot;">​</a></h3><ul><li><strong>Pros:</strong> Highly decoupled, faster performance (asynchronous), easier to add new services without changing existing ones.</li><li><strong>Cons:</strong> Harder to monitor the overall &quot;big picture,&quot; debugging can be complex (requires distributed tracing), potential for &quot;event spaghetti.&quot;</li></ul><hr><h2 id="summary-comparison" tabindex="-1">Summary Comparison <a class="header-anchor" href="#summary-comparison" aria-label="Permalink to &quot;Summary Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Feature</strong></th><th><strong>Orchestration</strong></th><th><strong>Choreography</strong></th></tr></thead><tbody><tr><td><strong>Control</strong></td><td>Centralized (The Conductor)</td><td>Decentralized (The Dancers)</td></tr><tr><td><strong>Coupling</strong></td><td>Tighter (Services depend on Orchestrator)</td><td>Loose (Services depend on Events)</td></tr><tr><td><strong>Visibility</strong></td><td>High (State is in one place)</td><td>Low (Distributed across services)</td></tr><tr><td><strong>Failure Handling</strong></td><td>Managed by Orchestrator</td><td>Managed by each service (Sagas)</td></tr><tr><td><strong>Best For</strong></td><td>Complex business workflows</td><td>Highly scalable, evolving systems</td></tr></tbody></table><h2 id="how-saga-relates-to-orchestration-and-choreography" tabindex="-1">How Saga Relates to Orchestration and Choreography <a class="header-anchor" href="#how-saga-relates-to-orchestration-and-choreography" aria-label="Permalink to &quot;How Saga Relates to Orchestration and Choreography&quot;">​</a></h2><p>The Saga pattern isn&#39;t a third alternative; rather, it is <strong>implemented using</strong> one of the two patterns we discussed. You choose the &quot;flavor&quot; of your Saga based on your communication style.</p><h3 id="orchestrated-saga-centralized-control" tabindex="-1">Orchestrated Saga (Centralized Control) <a class="header-anchor" href="#orchestrated-saga-centralized-control" aria-label="Permalink to &quot;Orchestrated Saga (Centralized Control)&quot;">​</a></h3><p>In this model, the <strong>Orchestrator</strong> acts as the Saga Manager. It tells Service A to &quot;Do X.&quot; If Service A fails, the Orchestrator tells Service B to &quot;Undo Y.&quot;</p><p><strong>When to use:</strong> For complex workflows where you need a single &quot;source of truth&quot; for the transaction state.</p>',10)),(a(),i(d,null,{default:t(()=>[h(s,{id:"mermaid-155",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20O%20as%20Saga%20Orchestrator%0A%20%20%20%20participant%20I%20as%20Inventory%0A%20%20%20%20participant%20P%20as%20Payment%0A%0A%20%20%20%20Note%20over%20O%2CP%3A%20Happy%20Path%0A%20%20%20%20O-%3E%3EI%3A%201.%20Reserve%20Item%0A%20%20%20%20I--%3E%3EO%3A%20Success%0A%20%20%20%20O-%3E%3EP%3A%202.%20Process%20Payment%0A%20%20%20%20P--%3E%3EO%3A%20FAIL!%0A%20%20%20%20%0A%20%20%20%20Note%20over%20O%2CP%3A%20Compensating%20Path%20(The%20Saga)%0A%20%20%20%20O-%3E%3EI%3A%203.%20Undo%20Inventory%20Reservation%0A%20%20%20%20I--%3E%3EO%3A%20Inventory%20Restored%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[r(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=o("h3",{id:"choreographed-saga-decentralized-events",tabindex:"-1"},[r("Choreographed Saga (Decentralized Events) "),o("a",{class:"header-anchor",href:"#choreographed-saga-decentralized-events","aria-label":'Permalink to "Choreographed Saga (Decentralized Events)"'},"​")],-1)),e[8]||(e[8]=o("p",null,'In this model, there is no manager. Services listen to events and decide if they need to trigger a "Success" action or a "Compensating" action based on what happened before them.',-1)),e[9]||(e[9]=o("p",null,[o("strong",null,"When to use:"),r(" For simple workflows where high decoupling and performance are the priority.")],-1)),(a(),i(d,null,{default:t(()=>[h(s,{id:"mermaid-165",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20%25%25%20Services%0A%20%20%20%20OS%5BOrder%20Service%5D%0A%20%20%20%20IS%5BInventory%20Service%5D%0A%20%20%20%20PS%5BPayment%20Service%5D%0A%0A%20%20%20%20%25%25%20Broker%0A%20%20%20%20subgraph%20EB%20%5BMessage%20Broker%5D%0A%20%20%20%20%20%20%20%20Fail((PaymentFailed%20Event))%0A%20%20%20%20end%0A%0A%20%20%20%20%25%25%20The%20Failure%20Flow%0A%20%20%20%20PS%20--%20%221.%20Payment%20Fails%20-%3E%20Publishes%22%20--%3E%20Fail%0A%20%20%20%20%0A%20%20%20%20%25%25%20The%20Saga%20(Rollback)%0A%20%20%20%20Fail%20--%20%222.%20Notify%22%20--%3E%20IS%0A%20%20%20%20Fail%20--%20%223.%20Notify%22%20--%3E%20OS%0A%0A%20%20%20%20%25%25%20Internal%20Actions%0A%20%20%20%20subgraph%20Actions%20%5BCompensating%20Actions%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20A1%5BIS%3A%20Restock%20Items%5D%0A%20%20%20%20%20%20%20%20A2%5BOS%3A%20Cancel%20Order%5D%0A%20%20%20%20end%0A%20%20%20%20%0A%20%20%20%20IS%20-.-%3E%20A1%0A%20%20%20%20OS%20-.-%3E%20A2%0A%0A%20%20%20%20style%20Fail%20fill%3A%23f96%2Cstroke%3A%23333%0A%20%20%20%20style%20Actions%20fill%3A%23f5f5f5%2Cstroke-dasharray%3A%205%205%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[r(" Loading... ",-1)])]),_:1})),e[10]||(e[10]=n('<h3 id="comparison-summary" tabindex="-1">Comparison Summary <a class="header-anchor" href="#comparison-summary" aria-label="Permalink to &quot;Comparison Summary&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>Feature</strong></th><th><strong>Orchestrated Saga</strong></th><th><strong>Choreographed Saga</strong></th></tr></thead><tbody><tr><td><strong>Logic Location</strong></td><td>Inside the Orchestrator</td><td>Spread across all services</td></tr><tr><td><strong>Visibility</strong></td><td>Easy to see the transaction status</td><td>Hard to see the full &quot;saga&quot; flow</td></tr><tr><td><strong>Complexity</strong></td><td>Becomes complex to maintain code</td><td>Becomes complex to trace events</td></tr><tr><td><strong>Coupling</strong></td><td>Orchestrator knows all services</td><td>Services only know events</td></tr></tbody></table>',2))])}const E=c(p,[["render",m]]);export{b as __pageData,E as default};
